  "atomic_requirements": [
    {
      "atomic_id": "SFR-001-001",
      "action_type": "준수",
      "output_name": "최소 요구조건·변경·증감 협의",
      "source_text": "최소한의 요구조건이며, 세부 요구사항에 제시되지 않은 사항이라도 향후 개발단계에서 상호 협의를 통해 변경 혹은 증감이 가능하다."
    },
    {
      "atomic_id": "SFR-001-002",
      "action_type": "준수",
      "output_name": "타 대학 분석·최적화 홈페이지 구축",
      "source_text": "타 대학 분석 등을 활용하여 우리 대학에 최적화된 홈페이지 구축방안을 마련하고 추진하여야 한다."
    },
    {
      "atomic_id": "SFR-001-003",
      "action_type": "준수",
      "output_name": "전자정부 표준프레임워크·반응형 웹",
      "source_text": "전자정부 표준프레임워크 기반의 반응형 웹 기술을 적용하여야 한다."
    },
    {
      "atomic_id": "SFR-001-004",
      "action_type": "준수",
      "output_name": "CMS·웹 접근성·호환성·표준문법",
      "source_text": "구축되는 모든 홈페이지는 전자정부 표준프레임워크 기반 콘텐츠관리시스템(CMS) 상에서 생성·관리·운영되어야 하며, 웹 접근성, 웹 호환성 및 표준문법을 준수하여야 한다."
    },
    {
      "atomic_id": "SFR-001-005",
      "action_type": "제공",
      "output_name": "수요기관 콘텐츠 활용 개발",
      "source_text": "홈페이지에서 게시되는 콘텐츠는 수요기관에서 제공하는 콘텐츠를 활용하여 개발하여야 한다."
    },
    {
      "atomic_id": "SFR-001-006",
      "action_type": "준수",
      "output_name": "홈페이지 이미지 저작권",
      "source_text": "홈페이지 내 이미지(일러스트, 사진 등)는 직접 제작 및 수집하여 저작권에 문제가 발생하지 않도록 하여야 한다."
    },
    {
      "atomic_id": "SFR-001-007",
      "action_type": "분석",
      "output_name": "웹 로그 분석·이용률·방문경로·에러",
      "source_text": "웹 로그 분석을 통하여 이용률 추이, 방문경로, 에러 내용 등을 분석하여 웹 사이트가 관리될 수 있도록 하여야 한다."
    },
    {
      "atomic_id": "SFR-001-008",
      "action_type": "보안",
      "output_name": "개인정보 동의·SSL 암호화",
      "source_text": "개인정보가 수집·이용을 필요로 하는 기능의 경우 개인정보 동의 절차를 반영하여야 한다.(시설 대관, 수강신청 등)\n개인정보, 비밀번호 등 송수신할 때는 SSL 인증서를 통해 암호화하여 전송하여야 한다."
    }
  ]
}
